                  >
                    <div className="school-instructor-avatar">
                      <User size={32} />
                    </div>
                    <div>
                      <div
                        className="fw-bold"
                        style={{ fontSize: "1.1rem", marginBottom: "0.25rem" }}
                      >
                        {instructor.name}
                      </div>
                      <div className="text-secondary small">
                        {instructor.role}
                      </div>
                    </div>
                    {selectedInstructor === instructor.name && (
                      <motion.div
