                        disabled={isPast}
                        onClick={() => {
                          setSelectedDate(dateKey);
                          setSelectedTime(null);
                        }}
                        className={`calendar-cell ${isSelected ? "selected" : ""} ${isToday ? "today" : ""} ${hasAvail ? "has-avail" : ""}`}
