                              onChange={(e) =>
                                updateGuardian(index, "email", e.target.value)
                              }
                              required
                            />
                            {formData.guardians.length > 1 && (
                              <button
                                type="button"
                                onClick={() => removeGuardian(index)}
                                className="btn btn-secondary"
                              >
                                �
                              </button>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </motion.div>
                )}

                <div className="d-flex gap-3 mt-5">
                  <button
                    type="button"
