                    <Calendar size={24} />
                  </div>
                  <div>
                    <div
                      className="text-secondary small text-uppercase fw-bold mb-1"
                      style={{ letterSpacing: "0.05em" }}
                    >
                      Lesson Date
                    </div>
                    <div className="fw-bold" style={{ fontSize: "1.1rem" }}>
                      {new Date(selectedDate! + "T00:00:00").toLocaleDateString(
                        "en-US",
                        { weekday: "long", month: "long", day: "numeric" },
                      )}
                    </div>
                    <div className="text-secondary">
                      {selectedTime} (2-Hour Session)
                    </div>
                  </div>
                </div>

                <div className="success-detail-item">
                  <div className="success-detail-icon">
                    <User size={24} />
                  </div>
                  <div>
                    <div
                      className="text-secondary small text-uppercase fw-bold mb-1"
                      style={{ letterSpacing: "0.05em" }}
                    >
                      Instructor
                    </div>
                    <div className="fw-bold" style={{ fontSize: "1.1rem" }}>
                      {selectedInstructor}
                    </div>
                  </div>
                </div>

                <div className="success-detail-item mb-0">
                  <div className="success-detail-icon">
                    <MapPin size={24} />
                  </div>
                  <div>
                    <div
                      className="text-secondary small text-uppercase fw-bold mb-1"
                      style={{ letterSpacing: "0.05em" }}
                    >
                      Pickup Point
                    </div>
                    <div className="fw-bold" style={{ fontSize: "1.1rem" }}>
                      {formData.pickupLocation}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-5 d-flex gap-3 justify-content-center">
                <motion.button
                  onClick={() => {
                    setBookingStep(0);
                    setSelectedInstructor(null);
                    setSelectedDate(null);
                    setSelectedTime(null);
                    setFormData({
                      name: "",
                      email: "",
                      phone: "",
                      birthdate: "",
                      permitNumber: "",
                      pickupLocation: "",
                      paymentMethod: "",
                      guardians: [{ name: "", phone: "", email: "" }],
                      referralCode:
                        localStorage.getItem("school_pending_referral") || "",
                    });
                  }}
                  className="btn btn-secondary"
                  style={{ padding: "1rem 2rem" }}
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                >
                  Book Another
                </motion.button>
                <motion.button
                  onClick={() => (window.location.href = "/portal")}
                  className="btn btn-primary"
                  style={{ padding: "1rem 2rem" }}
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                >
                  Go to Student Portal
                </motion.button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </section>
  );
};

